<template>
  <div
    v-if="open"
    class="sp-overlay"
    @pointerdown="onOverlayPointerDown"
    @pointerup="onOverlayPointerUp"
    @click.self="onOverlayClick"
  >
    <div class="sp-panel" role="dialog" aria-modal="true" :aria-label="paletteLabel">
      <div class="sp-input-row">
        <i class="fa fa-search sp-input-icon" aria-hidden="true"></i>
        <input
          ref="input"
          v-model="query"
          class="sp-input"
          type="text"
          :placeholder="inputPlaceholder"
          autocomplete="off"
          autocorrect="off"
          spellcheck="false"
          :aria-label="inputLabel"
          @compositionstart="composing = true"
          @compositionend="composing = false"
          @keydown="onInputKeydown($event)"
          @keydown.down="onArrow($event, 1)"
          @keydown.up="onArrow($event, -1)"
          @keydown.enter="onEnter($event)"
        />
        <kbd class="sp-esc" @click="close">esc</kbd>
      </div>

      <div class="sp-modes">
        <button
          type="button"
          class="sp-mode"
          :class="{ active: mode === 'ask' }"
          @click="setMode('ask')"
        >✦ Ask</button>
        <button
          type="button"
          class="sp-mode"
          :class="{ active: mode === 'search' }"
          @click="setMode('search')"
        >Search</button>
        <span v-if="semStatus" class="sp-mode-status">{{ semStatus }}</span>
      </div>

      <div ref="results" class="sp-results">
        <template v-if="mode !== 'ask'">
          <template v-if="query.trim() && groups.length">
            <div v-for="g in groups" :key="g.page" class="sp-group">
              <div class="sp-group-label">{{ g.page }}</div>
              <button
                v-for="r in g.items"
                :key="r.flatIndex"
                class="sp-result"
                :class="{ active: r.flatIndex === activeIndex }"
                :ref="el => setRowRef(el, r.flatIndex)"
                @mousemove="activeIndex = r.flatIndex"
                @click="go(r.route, r.anchor)"
              >
                <span class="sp-result-title" v-html="r.titleHtml"></span>
                <span v-if="r.snippetHtml" class="sp-result-snippet" v-html="r.snippetHtml"></span>
              </button>
            </div>
          </template>

          <div v-else-if="query.trim() && semBusy" class="sp-empty">
            {{ semLoading ? 'Loading model…' : 'Searching…' }}
          </div>

          <div v-else-if="query.trim()" class="sp-empty">
            No matches for &ldquo;{{ query.trim() }}&rdquo;.
          </div>

          <div v-else class="sp-group">
            <div class="sp-group-label">Jump to</div>
            <button
              v-for="s in suggestions"
              :key="s.route"
              class="sp-result"
              @click="go(s.route, '')"
            >
              <span class="sp-result-title">{{ s.label }}</span>
            </button>
          </div>
        </template>

        <div v-else class="sp-ask">
          <div v-if="!askReady" class="sp-empty">
            Ask isn&rsquo;t set up yet. Deploy the Worker, then set the endpoint.
          </div>
          <template v-else>
            <p v-if="answerText" class="sp-ask-answer">{{ answerText }}</p>
            <div v-else-if="askBusy" class="sp-empty">{{ askStatus }}</div>
            <div v-else-if="askError" class="sp-empty">Something went wrong. Press Enter to try again.</div>
            <div v-else class="sp-empty sp-ask-empty">
              <button
                type="button"
                class="sp-ask-sample"
                :class="{ visible: sampleVisible }"
                @click="useCurrentSample"
              >{{ currentSamplePrompt }}</button>
            </div>

            <div v-if="citedSources.length && !askBusy" class="sp-ask-sources">
              <div class="sp-group-label">Sources</div>
              <button
                v-for="s in citedSources"
                :key="s.id"
                class="sp-ask-source"
                @click="go(s.route, s.anchor)"
              >{{ s.page }} › {{ s.title }}</button>
            </div>
          </template>
        </div>
      </div>

      <div class="sp-foot">
        <span><kbd>⌥</kbd> mode</span>
        <span><kbd>&crarr;</kbd> {{ mode === 'ask' ? 'ask' : 'open' }}</span>
        <span v-if="mode !== 'ask'"><kbd>&uarr;</kbd><kbd>&darr;</kbd> move</span>
        <span><kbd>esc</kbd> close</span>
      </div>
    </div>
  </div>
</template>

<script>
import Fuse from 'fuse.js';
import { ensureReady, semanticRank } from '../utils/semanticSearch';
import { askConfigured, askStream } from '../utils/askSite';
import {
  allAskContexts,
  citedSourcesFromAnswer,
  cleanAskContextText,
  stripAnswerCitations,
} from '../utils/askRetrieval';

function slugify(s) {
  let out = '';
  let lastDash = true;
  const text = String(s).replace(/<[^>]+>/g, '').toLowerCase().trim();
  for (const c of text) {
    const ok = (c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c === '_';
    if (ok) {
      out += c;
      lastDash = false;
    } else if (!lastDash) {
      out += '-';
      lastDash = true;
    }
  }
  while (out.endsWith('-')) out = out.slice(0, -1);
  return out.slice(0, 80);
}

function holdAtTop(target) {
  let live = true;
  const reSnap = () => { if (live && target.isConnected) target.scrollIntoView({ behavior: 'auto', block: 'start' }); };
  const stop = () => {
    live = false;
    window.removeEventListener('wheel', stop);
    window.removeEventListener('touchstart', stop);
    window.removeEventListener('keydown', stop);
  };
  window.addEventListener('wheel', stop, { passive: true });
  window.addEventListener('touchstart', stop, { passive: true });
  window.addEventListener('keydown', stop);
  const root = document.querySelector('.content-container') || document;
  [...root.querySelectorAll('img')].filter(im => !im.complete).forEach(im => {
    im.addEventListener('load', reSnap, { once: true });
    im.addEventListener('error', reSnap, { once: true });
  });
  [150, 400, 800, 1300, 1900].forEach(t => setTimeout(reSnap, t));
  setTimeout(stop, 2400);
}

const STOP = new Set([
  'the', 'a', 'an', 'of', 'on', 'in', 'to', 'is', 'are', 'was', 'were', 'be',
  'and', 'or', 'for', 'with', 'at', 'by', 'from', 'as', 'it', 'i', 'my', 'me',
  'this', 'that', 'how', 'what', 'we', 'you', 'they', 'but', 'so', 'if', 'into',
  'about', 'out', 'up', 'over', 'than', 'then', 'has', 'have', 'had', 'do',
]);

export default {
  name: 'SearchPalette',
  data() {
    return {
      open: false,
      query: '',
      savedQueries: { search: '', ask: '' },
      items: [],
      fuse: null,
      loaded: false,
      activeIndex: 0,
      rowRefs: {},
      composing: false,
      mode: 'ask',
      semHits: [],
      semLoading: false,
      semQuerying: false,
      semError: '',
      askAnswer: '',
      askSources: [],
      askBusy: false,
      askError: '',
      askStatus: '',
      overlayPointerStartedOutside: false,
      overlayPointerEndedOutside: false,
      sampleVisible: true,
      sampleIndex: 0,
      samplePrompts: [
        'What is Henry\'s research about?',
        'Which papers has Henry written?',
        'How does Henry connect cognitive science and AI?',
        'What projects has Henry built?',
        'Where has Henry studied?',
        'What did Henry do at PwC and HSBC?',
        'What is Henry\'s work on mechanistic interpretability?',
      ],
      suggestions: [
        { label: 'About', route: '/about' },
        { label: 'Education', route: '/education' },
        { label: 'Experience', route: '/experience' },
        { label: 'Research', route: '/research' },
        { label: 'Projects', route: '/projects' },
        { label: 'CV', route: '/cv' },
      ],
    };
  },
  computed: {
    itemsById() {
      const m = {};
      for (const it of this.items) m[it.id] = it;
      return m;
    },
    semBusy() {
      return this.semLoading || this.semQuerying;
    },
    semStatus() {
      if (this.semError) return 'offline';
      if (this.semLoading) return 'loading model…';
      return '';
    },
    paletteLabel() {
      return this.mode === 'ask' ? 'Ask this site' : 'Search the site';
    },
    inputLabel() {
      return this.mode === 'ask' ? 'Ask question' : 'Search query';
    },
    inputPlaceholder() {
      return this.mode === 'ask' ? 'Ask anything about Henry...' : 'Search the site...';
    },
    askReady() {
      return askConfigured();
    },
    answerText() {
      return stripAnswerCitations(this.askAnswer);
    },
    citedSources() {
      return citedSourcesFromAnswer(this.askAnswer, this.askSources);
    },
    currentSamplePrompt() {
      return this.samplePrompts[this.sampleIndex] || '';
    },
    results() {
      if (this.mode === 'ask') return [];
      const q = this.query.trim();
      if (!q) return [];
      return this.hybridIds(q).map(id => this.itemsById[id]).filter(Boolean).slice(0, 12);
    },
    groups() {
      const out = [];
      const byPage = new Map();
      for (const item of this.results) {
        const titleHtml = this.highlight(item.title);
        const snippetHtml = this.snippet(item.body) || this.leadSnippet(item.body);
        const row = { ...item, titleHtml, snippetHtml };
        if (!byPage.has(item.page)) {
          const g = { page: item.page, items: [] };
          byPage.set(item.page, g);
          out.push(g);
        }
        byPage.get(item.page).items.push(row);
      }
      let fi = 0;
      for (const group of out) {
        for (const item of group.items) item.flatIndex = fi++;
      }
      return out;
    },
    flatList() {
      return this.groups.flatMap(g => g.items);
    },
  },
  watch: {
    query() {
      this.activeIndex = 0;
      if (this.mode === 'search' && this.query.trim()) {
        this.warmSemantic();
        this.scheduleSemantic();
      }
    },
  },
  mounted() {
    this._semSeq = 0;
    this._askSeq = 0;
    this._sampleTimer = window.setInterval(this.rotateSample, 3200);
    window.addEventListener('keydown', this.onKey);
  },
  unmounted() {
    window.removeEventListener('keydown', this.onKey);
    window.clearInterval(this._sampleTimer);
    window.clearTimeout(this._sampleFadeTimer);
    this.unlockScroll();
  },
  methods: {
    onOverlayPointerDown(e) {
      this.overlayPointerStartedOutside = !this.isInsidePanel(e.target);
      this.overlayPointerEndedOutside = false;
    },
    onOverlayPointerUp(e) {
      this.overlayPointerEndedOutside = !this.isInsidePanel(e.target);
    },
    onOverlayClick(e) {
      if (this.overlayPointerStartedOutside && this.overlayPointerEndedOutside) {
        this.close();
      } else {
        e.preventDefault();
        e.stopPropagation();
      }
      this.overlayPointerStartedOutside = false;
      this.overlayPointerEndedOutside = false;
    },
    isInsidePanel(target) {
      return !!(target && target.closest && target.closest('.sp-panel'));
    },
    onKey(e) {
      const k = e.key.toLowerCase();
      if ((e.metaKey || e.ctrlKey) && k === 'k') {
        e.preventDefault();
        this.toggle();
      } else if (e.key === 'Escape' && this.open) {
        this.close();
      } else if (e.key === '/' && !this.open && !this.isTyping(e)) {
        e.preventDefault();
        this.openPalette();
      }
    },
    isTyping(e) {
      const t = e.target;
      return t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable);
    },
    async loadIndex() {
      if (this.loaded) return;
      try {
        const res = await fetch('/assets/search-index.json', { cache: 'no-cache' });
        this.items = await res.json();
        this.fuse = new Fuse(this.items, {
          keys: [{ name: 'title', weight: 0.7 }, { name: 'body', weight: 0.3 }],
          threshold: 0.3,
          ignoreLocation: true,
          minMatchCharLength: 2,
        });
        this.loaded = true;
      } catch (err) {
        console.error('search index load failed:', err);
      }
    },
    toggle() {
      this.open ? this.close() : this.openPalette();
    },
    openPalette() {
      this.open = true;
      this.sampleVisible = true;
      this.loadIndex();
      this.lockScroll();
      this.warmSemantic();
      this.$nextTick(() => this.$refs.input && this.$refs.input.focus());
    },
    openAsk(prefill) {
      this.open = true;
      this.sampleVisible = true;
      this.loadIndex();
      this.lockScroll();
      this.mode = 'ask';
      this.activeIndex = 0;
      this.askAnswer = '';
      this.askSources = [];
      this.askError = '';
      this.warmSemantic();
      if (prefill && prefill.trim()) {
        this.query = prefill.trim();
        this.$nextTick(() => this.askQuestion());
      } else {
        this.query = '';
        this.$nextTick(() => this.$refs.input && this.$refs.input.focus());
      }
    },
    close() {
      this.open = false;
      this.unlockScroll();
    },
    move(dir) {
      const n = this.flatList.length;
      if (!n) return;
      this.activeIndex = (this.activeIndex + dir + n) % n;
      this.$nextTick(() => {
        const el = this.rowRefs[this.activeIndex];
        if (el && el.scrollIntoView) el.scrollIntoView({ block: 'nearest' });
      });
    },
    isComposing(e) {
      return this.composing || e.isComposing || e.keyCode === 229;
    },
    onEnter(e) {
      if (this.isComposing(e)) return;
      e.preventDefault();
      if (this.mode === 'ask') this.askQuestion();
      else this.choose();
    },
    onArrow(e, dir) {
      if (this.isComposing(e)) return;
      e.preventDefault();
      this.move(dir);
    },
    onInputKeydown(e) {
      if (this.isComposing(e)) return;
      if (e.key !== 'Alt' || e.repeat) return;
      e.preventDefault();
      this.setMode(this.mode === 'ask' ? 'search' : 'ask');
    },
    choose() {
      const target = this.flatList[this.activeIndex];
      if (target) this.go(target.route, target.anchor);
    },
    setRowRef(el, i) {
      if (el) this.rowRefs[i] = el;
      else delete this.rowRefs[i];
    },
    go(route, anchor) {
      const samePage = this.$route.path === route;
      this.close();
      if (!samePage) this.$router.push(route);
      this.$nextTick(() => this.scrollTo(anchor, 0, samePage));
    },
    scrollTo(anchor, attempt, samePage) {
      this.assignAnchors();
      if (!anchor) {
        window.scrollTo({ top: 0, behavior: samePage ? 'smooth' : 'auto' });
        return;
      }
      const el = document.getElementById(anchor);
      if (el) {
        const target = this.scrollTargetFor(el);
        target.scrollIntoView({ behavior: samePage ? 'smooth' : 'auto', block: 'start' });
        this.flash(el);
        if (!samePage) holdAtTop(target);
        return;
      }
      if (attempt < 25) setTimeout(() => this.scrollTo(anchor, attempt + 1, samePage), 120);
    },
    scrollTargetFor(el) {
      const te = el.closest('.timeline-event');
      if (te) return te;
      if (el.matches && el.matches('li.title')) {
        const sec = el.closest('section');
        if (sec) return sec;
      }
      return el;
    },
    assignAnchors() {
      const root = document.querySelector('.content-container');
      if (!root) return;
      const useEntries = !!root.querySelector('li.title');
      const els = useEntries ? root.querySelectorAll('li.title') : root.querySelectorAll('h2, h3');
      const seen = new Set();
      els.forEach(el => {
        const base = slugify(el.textContent);
        if (!base) return;
        let slug = base;
        let n = 2;
        while (seen.has(slug)) slug = `${base}-${n++}`;
        seen.add(slug);
        el.id = slug;
      });
    },
    flash(el) {
      el.classList.add('search-flash');
      setTimeout(() => el.classList.remove('search-flash'), 1700);
    },
    lockScroll() {
      this._prevOverflow = document.body.style.overflow;
      document.body.style.overflow = 'hidden';
    },
    unlockScroll() {
      document.body.style.overflow = this._prevOverflow || '';
    },
    escapeHtml(s) {
      return String(s)
        .split('&').join('&amp;')
        .split('<').join('&lt;')
        .split('>').join('&gt;')
        .split(String.fromCharCode(34)).join('&quot;');
    },
    words(text) {
      const out = [];
      let word = '';
      for (const c of String(text).toLowerCase()) {
        const ok = (c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c === '_';
        if (ok) word += c;
        else if (word) { out.push(word); word = ''; }
      }
      if (word) out.push(word);
      return out;
    },
    tokens() {
      const all = this.words(this.query).filter(t => t.length >= 2);
      const meaningful = all.filter(t => !STOP.has(t));
      return meaningful.length ? meaningful : all;
    },
    highlight(text) {
      return this.escapeHtml(text);
    },
    snippet(body) {
      const lower = body.toLowerCase();
      let pos = -1;
      for (const t of [...this.tokens()].sort((a, b) => b.length - a.length)) {
        const found = lower.indexOf(t);
        if (found >= 0) { pos = found; break; }
      }
      if (pos < 0) return '';
      const start = Math.max(0, pos - 40);
      let s = body.slice(start, start + 170);
      if (start > 0) s = `…${s}`;
      if (start + 170 < body.length) s = `${s}…`;
      return this.highlight(s);
    },
    leadSnippet(body) {
      let s = body.slice(0, 170);
      if (body.length > 170) s = `${s}…`;
      return this.highlight(s);
    },
    setMode(m) {
      if (this.mode === m) return;
      this.savedQueries[this.mode] = this.query;
      this.mode = m;
      this.query = this.savedQueries[m] || '';
      this.activeIndex = 0;
      this.sampleVisible = true;
      if (m === 'search') {
        if (this.query.trim()) { this.warmSemantic(); this.scheduleSemantic(); }
      } else {
        this.warmSemantic();
      }
    },
    useCurrentSample() {
      this.query = this.currentSamplePrompt;
      this.$nextTick(() => this.$refs.input && this.$refs.input.focus());
    },
    rotateSample() {
      if (!this.open || this.mode !== 'ask' || this.query.trim() || this.answerText || this.askBusy || this.askError) return;
      this.sampleVisible = false;
      window.clearTimeout(this._sampleFadeTimer);
      this._sampleFadeTimer = window.setTimeout(() => {
        this.sampleIndex = (this.sampleIndex + 1) % this.samplePrompts.length;
        this.$nextTick(() => { this.sampleVisible = true; });
      }, 260);
    },
    async askQuestion() {
      const q = this.query.trim();
      if (!q || !this.askReady) return;
      const seq = ++this._askSeq;
      this.askBusy = true;
      this.askError = '';
      this.askAnswer = '';
      this.askSources = [];
      try {
        this.askStatus = 'Thinking…';
        const contexts = await allAskContexts(this.items);
        if (seq !== this._askSeq) return;
        this.askSources = contexts;
        const payload = contexts.map(c => ({ page: c.page, title: c.title, text: cleanAskContextText(c.body) }));
        for await (const tok of askStream(q, payload)) {
          if (seq !== this._askSeq) return;
          this.askAnswer += tok;
        }
      } catch (e) {
        if (seq === this._askSeq) this.askError = 'error';
        console.error('ask failed:', e);
      } finally {
        if (seq === this._askSeq) this.askBusy = false;
      }
    },
    hybridIds(q) {
      const K = 60;
      const W_LEX = 2;
      const W_SEM = 1;
      const score = new Map();
      const add = (ids, w) => ids.forEach((id, i) => score.set(id, (score.get(id) || 0) + w / (K + i)));
      if (this.fuse) add(this.fuse.search(q).slice(0, 20).map(r => r.item.id), W_LEX);
      add(this.semHits.map(h => h.id), W_SEM);
      return [...score.entries()].sort((a, b) => b[1] - a[1]).map(([id]) => id);
    },
    async warmSemantic() {
      if (this._semWarmed || this.semLoading) return;
      this.semLoading = true;
      this.semError = '';
      try {
        await ensureReady();
        this._semWarmed = true;
      } catch (e) {
        this.semError = 'offline';
        console.error('semantic warm-up failed:', e);
      } finally {
        this.semLoading = false;
      }
    },
    scheduleSemantic() {
      clearTimeout(this._semDebounce);
      this._semDebounce = setTimeout(() => this.runSemantic(), 250);
    },
    async runSemantic() {
      const q = this.query.trim();
      if (!q) { this.semHits = []; return; }
      const seq = ++this._semSeq;
      this.semQuerying = true;
      try {
        const hits = await semanticRank(q, 12);
        if (seq === this._semSeq) { this.semHits = hits; this.semError = ''; }
      } catch (e) {
        if (seq === this._semSeq) { this.semHits = []; this.semError = 'offline'; }
        console.error('semantic search failed:', e);
      } finally {
        if (seq === this._semSeq) this.semQuerying = false;
      }
    },
  },
};
</script>

